import csv
import os
from datetime import datetime
from typing import List, Dict, Any

import modal

app = modal.App("etl-pipeline-orchestrator")

volume = modal.Volume.from_name("etl-pipeline-orchestrator-vol", create_if_missing=True)
secret = modal.Secret.from_name("etl-pipeline-orchestrator-secret")
output_dict = modal.Dict.from_name("etl-pipeline-orchestrator-output", create_if_missing=True)

OUTPUT_PATH = "/data/output.csv"


@app.cls(secrets=[secret], volumes={"/data": volume})
class ETLPipeline:
    @modal.enter()
    def setup(self) -> None:
        self.output_path = OUTPUT_PATH
        self.db_url = os.environ.get("DB_URL", "")
        self.api_token = os.environ.get("API_TOKEN", "")

    @modal.method()
    def extract(self) -> List[Dict[str, Any]]:
        now = datetime.utcnow().isoformat()
        records = [
            {"id": 1, "source": "db", "payload": f"db:{self.db_url}", "ts": now},
            {"id": 2, "source": "api", "payload": f"api:{self.api_token}", "ts": now},
        ]
        return records

    @modal.method()
    def transform(self, records: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        transformed = []
        for record in records:
            transformed.append(
                {
                    "id": record["id"],
                    "source": record["source"].upper(),
                    "payload": record["payload"],
                    "ts": record["ts"],
                }
            )
        return transformed

    @modal.method()
    def load(self, records: List[Dict[str, Any]]) -> int:
        with open(self.output_path, "w", newline="") as handle:
            writer = csv.DictWriter(handle, fieldnames=["id", "source", "payload", "ts"])
            writer.writeheader()
            writer.writerows(records)
        volume.commit()
        return len(records)

    @modal.method()
    def run(self) -> Dict[str, Any]:
        records = self.extract()
        transformed = self.transform(records)
        records_loaded = self.load(transformed)
        return {
            "records_extracted": len(records),
            "records_loaded": records_loaded,
            "pipeline_status": "success",
            "output_path": self.output_path,
        }


@app.function(schedule=modal.Period(hours=1))
def scheduled_etl() -> None:
    ETLPipeline().run.remote()


@app.local_entrypoint()
def main() -> None:
    result = ETLPipeline().run.remote()
    output_dict.put("records_extracted", result["records_extracted"])
    output_dict.put("records_loaded", result["records_loaded"])
    output_dict.put("pipeline_status", result["pipeline_status"])
    output_dict.put("output_path", result["output_path"])
    print(result)
